#!/usr/bin/env python3
# Generated by aprog-private/scripts/generate_activities.py
# To update: edit quiz-data/const-refactor.json and re-run the generator.
"""Const Refactoring Sprint

Add const qualifiers to a working grid utility until the linter is satisfied.
"""
import os, shutil, subprocess, sys, tempfile, zipfile
import hashlib as _hl, hmac as _hm

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "76910f4e963f9111624491a3f0722461cd1c68682cd0a4b3dcfef0b9f917babde0dfc4d60038c11814b928684b5fedf8ad49dc8adb36a1f0"
_REQUIRED_CONST = 12

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac("sha256", key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b"", 0, b""
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)

def _count_const(repo_dir):
    try:
        r = subprocess.run(
            ["grep", "-o", r"\bconst\b", "grid.cpp"],
            capture_output=True, text=True, cwd=repo_dir,
        )
        return r.stdout.count("const")
    except Exception:
        return 0

def _has_const_cast(repo_dir):
    try:
        r = subprocess.run(
            ["grep", "-q", "const_cast", "grid.cpp"],
            capture_output=True, cwd=repo_dir,
        )
        return r.returncode == 0
    except Exception:
        return False

def _build(repo_dir):
    r = subprocess.run(["make"], capture_output=True, text=True, cwd=repo_dir)
    return r.returncode == 0, r.stderr

def _run_demo(repo_dir):
    try:
        r = subprocess.run(
            ["./grid_demo"], capture_output=True, text=True, timeout=10, cwd=repo_dir,
        )
        return r.stdout.strip(), None
    except subprocess.TimeoutExpired:
        return None, "timeout"
    except Exception as e:
        return None, str(e)

def main():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")

    work_dir = tempfile.mkdtemp(prefix="const-refactor-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    repo_dir = os.path.join(work_dir, entries[0])

    banner_text = """
      ============================================================
       Const Refactoring Sprint
      ============================================================

       A working grid utility -- but const-free.  Your job: add const everywhere it belongs.
       
         The header (grid.hpp) already shows the correct const-qualified signatures.
         Your task is to make grid.cpp match those signatures.
       
         Step 1 -- read grid.hpp to see the target signatures.
           cat grid.hpp
       
         Step 2 -- run the linter to see what needs fixing.
           ./lint.sh
       
         Step 3 -- edit grid.cpp, add const to one function at a time.
           Then recompile: make
       
         Step 4 -- repeat until the linter reports no findings.
           ./lint.sh
       
         When the linter is clean and 'make' succeeds, type 'exit'.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@const-refactor:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << \'BANNER\'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()

    shell = os.environ.get("SHELL", "/bin/bash")

    try:
        while True:
            subprocess.run([shell, "--rcfile", rcfile.name])

            print()
            _banner("Const Refactoring Sprint -- Checking Your Work")
            print()

            if _has_const_cast(repo_dir):
                print("  const_cast found in grid.cpp.")
                print("  Fix the type rather than casting away const.")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            cnt = _count_const(repo_dir)
            if cnt < _REQUIRED_CONST:
                print(f"  grid.cpp has {cnt} const keywords; need at least {_REQUIRED_CONST}.")
                print("  Run ./lint.sh inside the shell to see what is still missing.")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            build_ok, build_err = _build(repo_dir)
            if not build_ok:
                print("  make failed.  Fix the compilation errors first.")
                for line in build_err.strip().splitlines()[:10]:
                    print(f"    {line}")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            output, err = _run_demo(repo_dir)
            if output is None:
                print(f"  grid_demo did not run: {err}")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            passphrase = _decrypt(output)
            if passphrase is not None:
                _show_passphrase(passphrase)
                break

            print("  grid_demo ran but the output did not match.")
            print("  Check that each function returns the correct value.")
            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                break
            if again == "y":
                print()
                continue
            break

    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass
        shutil.rmtree(work_dir, ignore_errors=True)


if __name__ == "__main__":
    main()
